    lh t2,  2*6(a0)
    lh t3,  2*7(a0)
    plant_mul_const_inplace_x4  t5, t6, t6, t6, t6,  a1, a2, a3, a4
    lh a5,  2*8(a0)
    lh a6,  2*9(a0)
    lh a7, 2*10(a0)
    lh s0, 2*11(a0)
    sh a1,  2*0(a0)
    sh a2,  2*1(a0)
    sh a3,  2*2(a0)
    sh a4,  2*3(a0)
    plant_mul_const_inplace_x4  t5, t6, t6, t6, t6,  t0, t1, t2, t3
    lh a1,  2*12(a0)
    lh a2,  2*13(a0)
    lh a3,  2*14(a0)
    lh a4,  2*15(a0)
    sh t0,  2*4(a0)
    sh t1,  2*5(a0)
    sh t2,  2*6(a0)
    sh t3,  2*7(a0)
    plant_mul_const_inplace_x4  t5, t6, t6, t6, t6,  a5, a6, a7, s0
    sh a5,  2*8(a0)
    sh a6,  2*9(a0)
    sh a7,  2*10(a0)
    sh s0,  2*11(a0)
    plant_mul_const_inplace_x4  t5, t6, t6, t6, t6,  a1, a2, a3, a4
    sh a1,  2*12(a0)
    sh a2,  2*13(a0)
    sh a3,  2*14(a0)
    sh a4,  2*15(a0)
    addi a0, a0, 2*16
    addi t4, t4, -1
  bne t4, zero, poly_toplant_rv64im_loop
  ld   s0, 0(sp)
